  $('#hamburger').on('click', function () {
    $('#nav-links').toggleClass('open');
  });
  $('#nav-links a').on('click', function () {
    $('#nav-links').removeClass('open');
  });

  /* ── Scroll: navbar shrink + back-to-top ───────────────────────────── */
  $(window).on('scroll', function () {
    if ($(this).scrollTop() > 300) {
      $('#back-top').addClass('show');
    } else {
      $('#back-top').removeClass('show');
    }
  });

  $('#back-top').on('click', function () {
    $('html, body').animate({ scrollTop: 0 }, 500);
  });

  /* ── Fade-in on scroll (IntersectionObserver) ──────────────────────── */
  const observer = new IntersectionObserver(function (entries) {
    entries.forEach(function (entry) {
      if (entry.isIntersecting) {
        $(entry.target).addClass('visible');
        observer.unobserve(entry.target);
      }
    });
  }, { threshold: 0.1 });

  $('.fade-in').each(function () {
    observer.observe(this);
  });

  /* ── Newsletter ─────────────────────────────────────────────────────── */
  $('#nl-form').on('submit', function (e) {
    e.preventDefault();
    var email = $('#nl-email').val().trim();
    if (!email) return;
    $('#nl-msg').html('<i class="fas fa-check-circle"></i> Obrigado! Você será avisado das novidades.');
    $('#nl-email').val('');
    setTimeout(function () { $('#nl-msg').text(''); }, 5000);
  });

  /* ── Smooth scroll para âncoras internas ────────────────────────────── */
  $('a[href^="#"]').on('click', function (e) {
    var target = $(this.getAttribute('href'));
    if (target.length) {
      e.preventDefault();
      $('html, body').animate({ scrollTop: target.offset().top - 70 }, 500);
    }
  });

